import { NumberField as NumberFieldPrimitive } from '@base-ui/react/number-field';
import { MinusIcon, PlusIcon, ScrubCursorIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './NumberField.module.css';

type NumberFieldProps = NumberFieldPrimitive.Root.Props & {
  decrementLabel?: string;
  incrementLabel?: string;
};

function NumberFieldRoot({ className, ...props }: NumberFieldPrimitive.Root.Props) {
  return (
    <NumberFieldPrimitive.Root
      data-slot="number-field-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
}

function NumberField({
  className,
  children,
  decrementLabel = 'Decrease value',
  incrementLabel = 'Increase value',
  ...props
}: NumberFieldProps) {
  return (
    <NumberFieldRoot className={className} {...props}>
      {children}
      <NumberFieldGroup>
        <NumberFieldDecrement aria-label={decrementLabel} />
        <NumberFieldInput />
        <NumberFieldIncrement aria-label={incrementLabel} />
      </NumberFieldGroup>
    </NumberFieldRoot>
  );
}

function NumberFieldScrubArea({ className, ...props }: NumberFieldPrimitive.ScrubArea.Props) {
  return (
    <NumberFieldPrimitive.ScrubArea
      data-slot="number-field-scrub-area"
      className={mergeClassName(className, styles.scrubArea)}
      {...props}
    />
  );
}

function NumberFieldScrubAreaCursor({
  className,
  children,
  ...props
}: NumberFieldPrimitive.ScrubAreaCursor.Props) {
  return (
    <NumberFieldPrimitive.ScrubAreaCursor
      data-slot="number-field-scrub-area-cursor"
      className={mergeClassName(className, styles.scrubAreaCursor)}
      {...props}
    >
      {children ?? <ScrubCursorIcon />}
    </NumberFieldPrimitive.ScrubAreaCursor>
  );
}

function NumberFieldGroup({ className, ...props }: NumberFieldPrimitive.Group.Props) {
  return (
    <NumberFieldPrimitive.Group
      data-slot="number-field-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
}

function NumberFieldDecrement({
  className,
  children,
  'aria-label': ariaLabel = 'Decrease value',
  ...props
}: NumberFieldPrimitive.Decrement.Props) {
  return (
    <NumberFieldPrimitive.Decrement
      data-slot="number-field-decrement"
      aria-label={ariaLabel}
      className={mergeClassName(className, styles.decrement)}
      {...props}
    >
      {children ?? <MinusIcon />}
    </NumberFieldPrimitive.Decrement>
  );
}

function NumberFieldInput({ className, ...props }: NumberFieldPrimitive.Input.Props) {
  return (
    <NumberFieldPrimitive.Input
      data-slot="number-field-input"
      className={mergeClassName(className, styles.input)}
      {...props}
    />
  );
}

function NumberFieldIncrement({
  className,
  children,
  'aria-label': ariaLabel = 'Increase value',
  ...props
}: NumberFieldPrimitive.Increment.Props) {
  return (
    <NumberFieldPrimitive.Increment
      data-slot="number-field-increment"
      aria-label={ariaLabel}
      className={mergeClassName(className, styles.increment)}
      {...props}
    >
      {children ?? <PlusIcon />}
    </NumberFieldPrimitive.Increment>
  );
}

export {
  NumberField,
  NumberFieldRoot,
  NumberFieldScrubArea,
  NumberFieldScrubAreaCursor,
  NumberFieldGroup,
  NumberFieldDecrement,
  NumberFieldInput,
  NumberFieldIncrement,
};
export type { NumberFieldProps };

@layer ui.components {
  .root {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--number-field-gap, var(--spacing-1));
    width: var(--number-field-width, auto);
    max-width: var(--number-field-max-width, none);
  }

  .scrubArea {
    display: inline-flex;
    align-items: center;
    gap: var(--number-field-scrub-area-gap, var(--spacing-2));
    color: var(--number-field-scrub-area-color, var(--color-foreground));
    user-select: none;
    cursor: ew-resize;

    &:is([data-disabled], [data-readonly]) {
      cursor: default;
      opacity: var(--number-field-disabled-opacity, var(--opacity-disabled));
    }
  }

  .scrubAreaCursor {
    display: inline-flex;
    width: var(--number-field-scrub-area-cursor-size, 1.5rem);
    height: var(--number-field-scrub-area-cursor-size, 1.5rem);
    align-items: center;
    justify-content: center;
    flex-shrink: 0;

    & > svg {
      width: 100%;
      height: 100%;
    }
  }

  .group {
    display: inline-flex;
    align-items: stretch;
  }

  .decrement,
  .increment {
    --_number-field-focus-ring-width: var(
      --number-field-focus-ring-width,
      var(--number-field-border-width, var(--border-width-sm))
    );

    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--number-field-control-height, var(--size-lg));
    min-width: var(--number-field-control-height, var(--size-lg));
    height: var(--number-field-control-height, var(--size-lg));
    margin: 0;
    border: var(--number-field-border-width, var(--border-width-sm))
      var(--number-field-border-style, solid) var(--number-field-border-color, var(--color-border));
    padding: 0;
    background-color: var(--number-field-button-bg, var(--color-background));
    color: var(--number-field-button-color, var(--color-foreground));
    outline: 0;
    user-select: none;
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default),
      opacity var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--number-field-button-bg-hover, var(--color-accent));
      }
    }

    &:active {
      background-color: var(
        --number-field-button-bg-active,
        var(--number-field-button-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible {
      outline: var(--_number-field-focus-ring-width) solid
        var(--number-field-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--_number-field-focus-ring-width) * -1);
      z-index: 1;
    }

    &:is([data-disabled], [data-readonly], :disabled) {
      opacity: var(--number-field-disabled-opacity, var(--opacity-disabled));
      pointer-events: none;
    }

    &[data-invalid] {
      border-color: var(--number-field-border-color-invalid, var(--color-destructive));
    }

    & > svg {
      width: var(--number-field-icon-size, 0.875rem);
      height: var(--number-field-icon-size, 0.875rem);
      flex-shrink: 0;
    }
  }

  .decrement {
    border-radius: var(--number-field-radius, var(--radius-md)) 0 0
      var(--number-field-radius, var(--radius-md));
    border-right: 0;
  }

  .increment {
    border-radius: 0 var(--number-field-radius, var(--radius-md))
      var(--number-field-radius, var(--radius-md)) 0;
    border-left: 0;
  }

  .input {
    --_number-field-focus-ring-width: var(
      --number-field-focus-ring-width,
      var(--number-field-border-width, var(--border-width-sm))
    );

    box-sizing: border-box;
    width: var(--number-field-input-width, 6rem);
    height: var(--number-field-control-height, var(--size-lg));
    margin: 0;
    border-top: var(--number-field-border-width, var(--border-width-sm))
      var(--number-field-border-style, solid) var(--number-field-border-color, var(--color-border));
    border-bottom: var(--number-field-border-width, var(--border-width-sm))
      var(--number-field-border-style, solid) var(--number-field-border-color, var(--color-border));
    border-left: 0;
    border-right: 0;
    border-radius: 0;
    padding: var(--number-field-input-padding-y, 0.5rem)
      var(--number-field-input-padding-x, 0.75rem);
    background-color: var(--number-field-input-bg, var(--color-background));
    color: var(--number-field-input-color, var(--color-foreground));
    font: inherit;
    font-size: var(--number-field-input-font-size, var(--text-md));
    line-height: var(--number-field-input-line-height, var(--line-height-text-md));
    text-align: center;
    font-variant-numeric: tabular-nums;
    outline: var(--_number-field-focus-ring-width) solid transparent;
    outline-offset: calc(var(--_number-field-focus-ring-width) * -1);
    transition:
      border-color var(--transition-default),
      outline-color var(--transition-default),
      opacity var(--transition-default);

    &:focus-visible {
      outline-color: var(--number-field-focus-ring-color, var(--color-ring));
      z-index: 1;
    }

    &[data-invalid] {
      border-top-color: var(--number-field-border-color-invalid, var(--color-destructive));
      border-bottom-color: var(--number-field-border-color-invalid, var(--color-destructive));

      &:focus-visible {
        outline-color: var(--number-field-border-color-invalid, var(--color-destructive));
      }
    }

    &:is([data-disabled], [data-readonly]) {
      opacity: var(--number-field-disabled-opacity, var(--opacity-disabled));
    }
  }
}

export {
  NumberField,
  NumberFieldRoot,
  NumberFieldScrubArea,
  NumberFieldScrubAreaCursor,
  NumberFieldGroup,
  NumberFieldDecrement,
  NumberFieldInput,
  NumberFieldIncrement,
} from './NumberField';
export type { NumberFieldProps } from './NumberField';
